const length = widthMm * mm;
const height = heightMm * mm;
const depth = thicknessMm * mm;
const group = new THREE.Group();
const geo = new THREE.BoxGeometry(length, height, depth);
geo.translate(length / 2, height / 2, 0);
const mat = new THREE.MeshLambertMaterial({ color: '#D4B483' });
group.add(new THREE.Mesh(geo, mat));
return group;
